#define ED_HELP_COUNT (sizeof(ed_help) / sizeof(ed_help[0]))

static char *ed_help_text;
static uint32_t ed_help_widget_id;

// [=]===^=[ ed_find_help ]========================================[=]
static char *ed_find_help(uint32_t type) {
	for(uint32_t i = 0; i < ED_HELP_COUNT; ++i) {
		if(ed_help[i].type == type) {
			return ed_help[i].text;
		}
	}
	return NULL;
}

// [=]===^=[ ed_render_help_popup ]================================[=]
static void ed_render_help_popup(struct mkgui_ctx *ctx, void *userdata) {
	(void)userdata;
	if(!ed_help_text || !ed_help_widget_id) {
		return;
	}

	int32_t widx = find_widget_idx(ctx, ed_help_widget_id);
	if(widx < 0) {
		return;
	}

	int32_t bx = ctx->rects[widx].x;
	int32_t by = ctx->rects[widx].y + ctx->rects[widx].h + 4;
	int32_t max_w = 300;
	int32_t pad = 8;
	int32_t line_h = ctx->font_height + 2;

	char *src = ed_help_text;
	int32_t lines = 0;
	int32_t actual_w = 0;
	while(*src) {
		int32_t line_w = 0;
		char *line_start = src;
		char *last_break = NULL;
		while(*src && *src != '\n') {
			char tmp[2] = { *src, 0 };
			int32_t cw = text_width(ctx, tmp);
			if(line_w + cw > max_w - pad * 2) {
				if(last_break) {
					src = last_break + 1;
				}
				break;
			}

			if(*src == ' ') {
				last_break = src;
			}
			line_w += cw;
			++src;
		}

		if(*src == '\n') {
			++src;
		}

		if(src == line_start && *src) {
			++src;
		}

		if(line_w > actual_w) {
			actual_w = line_w;
		}
		++lines;
	}

	int32_t pw = actual_w + pad * 2;
	int32_t ph = lines * line_h + pad * 2;

	if(bx + pw > ctx->win_w) {
		bx = ctx->win_w - pw;
	}

	if(by + ph > ctx->win_h) {
		by = ctx->rects[widx].y - ph - 4;
	}

	if(bx < 0) {
		bx = 0;
	}

	if(by < 0) {
		by = 0;
	}

	draw_rounded_rect(ctx->pixels, ctx->win_w, ctx->win_h, bx, by, pw, ph, ctx->theme.menu_bg, ctx->theme.highlight, ctx->theme.corner_radius);

	src = ed_help_text;
	int32_t ty = by + pad;
	while(*src) {
		int32_t line_w = 0;
		char *line_start = src;
		char *last_break = NULL;
		char *line_end = src;
		while(*src && *src != '\n') {
			char tmp[2] = { *src, 0 };
			int32_t cw = text_width(ctx, tmp);
			if(line_w + cw > max_w - pad * 2) {
				if(last_break) {
					line_end = last_break;
					src = last_break + 1;
				} else {
					line_end = src;
				}
				break;
			}

			if(*src == ' ') {
				last_break = src;
			}
			line_w += cw;
			++src;
			line_end = src;
		}

		if(*src == '\n') {
			++src;
		}

		if(src == line_start && *src) {
			++src;
			line_end = src;
		}

		char line_buf[256];
		uint32_t len = (uint32_t)(line_end - line_start);
		if(len >= sizeof(line_buf)) {
			len = sizeof(line_buf) - 1;
		}
		memcpy(line_buf, line_start, len);
		line_buf[len] = '\0';
		push_text_clip(bx + pad, ty, line_buf, ctx->theme.text, bx, by, bx + pw, by + ph);
		ty += line_h;
	}
}

