// [=]===^=[ ed_compute_vis_mask ]=================================[=]
static uint32_t ed_compute_vis_mask(struct ed_widget *w) {
	uint32_t mask = 0;
	if(w->type == MKGUI_CHECKBOX || w->type == MKGUI_RADIO) {
		mask |= ED_VIS_HAS_CHECK;
	}

	if(w->type == MKGUI_MENUITEM) {
		mask |= ED_VIS_MENUITEM;
	}

	if(w->type == MKGUI_TABS) {
		mask |= ED_VIS_TABS;
	}

	if(w->type == MKGUI_TOOLBAR) {
		mask |= ED_VIS_TOOLBAR;
	}

	if(w->type == MKGUI_VBOX || w->type == MKGUI_HBOX) {
		mask |= ED_VIS_BOX;
	}

	if(w->type == MKGUI_VBOX || w->type == MKGUI_HBOX || w->type == MKGUI_FORM || w->type == MKGUI_PANEL || w->type == MKGUI_IMAGE || w->type == MKGUI_GLVIEW || w->type == MKGUI_CANVAS) {
		mask |= ED_VIS_BORDERABLE;
	}

	if(w->type == MKGUI_INPUT || w->type == MKGUI_TEXTAREA) {
		mask |= ED_VIS_INPUT;
	}

	if(w->type == MKGUI_INPUT) {
		mask |= ED_VIS_INPUT_ONLY;
	}

	if(w->type == MKGUI_LISTVIEW || w->type == MKGUI_GRIDVIEW || w->type == MKGUI_TREEVIEW) {
		mask |= ED_VIS_HAS_MULTI;
	}

	if(w->type == MKGUI_IMAGE) {
		mask |= ED_VIS_IMAGE;
	}

	if(w->type == MKGUI_PROGRESS) {
		mask |= ED_VIS_PROGRESS;
	}

	if(w->type == MKGUI_SLIDER || w->type == MKGUI_SCROLLBAR || w->type == MKGUI_METER) {
		mask |= ED_VIS_SLIDER;
	}

	if(w->type == MKGUI_SLIDER) {
		mask |= ED_VIS_SLIDER_ONLY;
	}

	if(w->type == MKGUI_METER) {
		mask |= ED_VIS_METER;
	}

	if(w->type == MKGUI_LABEL) {
		mask |= ED_VIS_LABEL;
	}

	if(w->type == MKGUI_GROUP) {
		mask |= ED_VIS_GROUP;
	}

	if(w->type == MKGUI_BUTTON || w->type == MKGUI_MENUITEM) {
		mask |= ED_VIS_ACCELABLE;
	}

	if(w->type == MKGUI_MENU || w->type == MKGUI_MENUITEM) {
		mask |= ED_VIS_MENU;
	}
	for(uint32_t i = 0; i < ed.widget_count; ++i) {
		if(ed.widgets[i].id == w->parent_id) {
			uint32_t pt = ed.widgets[i].type;
			if(pt == MKGUI_HSPLIT || pt == MKGUI_VSPLIT) {
				mask |= ED_VIS_IN_SPLIT;
			}

			if(pt == MKGUI_VBOX || pt == MKGUI_HBOX) {
				mask |= ED_VIS_IN_BOX;
			}

			if(pt == MKGUI_TOOLBAR) {
				mask |= ED_VIS_IN_TOOLBAR;
			}

			if(pt == MKGUI_TABS) {
				mask |= ED_VIS_TAB_CHILD;
			}
			break;
		}
	}
	return mask;
}

// [=]===^=[ ed_prop_visible ]=====================================[=]
static uint32_t ed_prop_visible(struct ed_prop_desc *p, uint32_t vis_mask) {
	return p->vis_mask == ED_VIS_ALWAYS || (vis_mask & p->vis_mask);
}

// [=]===^=[ ed_set_widget_vis ]===================================[=]
static void ed_set_widget_vis(struct mkgui_ctx *ctx, uint32_t id, uint32_t visible) {
	if(!id) {
		return;
	}
	struct mkgui_widget *w = find_widget(ctx, id);
	if(w) {
		if(visible) {
			w->flags &= ~MKGUI_HIDDEN;
		} else {
			w->flags |= MKGUI_HIDDEN;
		}
	}
}

// [=]===^=[ ed_sync_prop_value ]==================================[=]
static void ed_sync_prop_value(struct mkgui_ctx *ctx, struct ed_prop_desc *p, struct ed_widget *w) {
	switch(p->kind) {
		case ED_PK_LABEL: {
			mkgui_label_set(ctx, p->widget_id, ed_type_name(w->type));
		} break;

		case ED_PK_STRING:
		case ED_PK_STRING_BROWSE: {
			char *val = (char *)((char *)w + p->offset);
			mkgui_input_set(ctx, p->widget_id, val);
		} break;

		case ED_PK_INT32: {
			int32_t val = *(int32_t *)((char *)w + p->offset);
			mkgui_spinbox_set(ctx, p->widget_id, val);
		} break;

		case ED_PK_INT32_PAIR: {
			int32_t *vals = (int32_t *)((char *)w + p->offset);
			mkgui_spinbox_set(ctx, p->widget_id, vals[0]);
			mkgui_spinbox_set(ctx, p->widget_id2, vals[1]);
		} break;

		case ED_PK_FLAG: {
			struct mkgui_widget *fl = find_widget(ctx, p->widget_id);
			if(fl) {
				uint32_t *fld = (uint32_t *)((char *)w + p->offset);
				if(*fld & p->flag_bit) {
					fl->flags |= MKGUI_CHECKBOX_CHECKED;
				} else {
					fl->flags &= ~MKGUI_CHECKBOX_CHECKED;
				}
			}
		} break;

		case ED_PK_ALIGN: {
			uint32_t av = (w->flags & MKGUI_ALIGN_MASK) >> 25;
			struct mkgui_widget *drp = find_widget(ctx, p->widget_id);
			if(drp) {
				struct mkgui_dropdown_data *dd = find_dropdown_data(ctx, p->widget_id);
				if(dd) {
					dd->selected = (int32_t)av;
				}
			}
		} break;

		case ED_PK_TB_MODE: {
			uint32_t mode = w->style & MKGUI_TOOLBAR_MODE_MASK;
			struct mkgui_dropdown_data *dd = find_dropdown_data(ctx, p->widget_id);
			if(dd) {
				dd->selected = (int32_t)mode;
			}
		} break;

		case ED_PK_ACCEL: {
			if(w->accel_keysym) {
				char buf[64];
				accel_format_text(w->accel_keymod, w->accel_keysym, buf, sizeof(buf));
				mkgui_button_set_text(ctx, p->widget_id, buf);
			} else {
				mkgui_button_set_text(ctx, p->widget_id, "None");
			}
		} break;

		default: break;
	}
}

// [=]===^=[ ed_read_prop_value ]==================================[=]
static void ed_read_prop_value(struct mkgui_ctx *ctx, struct ed_prop_desc *p, struct ed_widget *w) {
	switch(p->kind) {
		case ED_PK_STRING:
		case ED_PK_STRING_BROWSE: {
			char *val = mkgui_input_get(ctx, p->widget_id);
			if(val) {
				char *dst = (char *)w + p->offset;
				size_t cap;
				if(p->offset == offsetof(struct ed_widget, id_name)) {
					cap = sizeof(w->id_name);
				} else if(p->offset == offsetof(struct ed_widget, label)) {
					cap = sizeof(w->label);
				} else {
					cap = sizeof(w->icon);
				}
				size_t slen = strlen(val);
				if(slen >= cap) {
					slen = cap - 1;
				}
				memcpy(dst, val, slen);
				dst[slen] = '\0';
				if(p->offset == offsetof(struct ed_widget, label)) {
					w->label_tw = -1;
				}
			}
		} break;

		case ED_PK_INT32: {
			int32_t *dst = (int32_t *)((char *)w + p->offset);
			*dst = mkgui_spinbox_get(ctx, p->widget_id);
		} break;

		case ED_PK_INT32_PAIR: {
			int32_t *vals = (int32_t *)((char *)w + p->offset);
			vals[0] = mkgui_spinbox_get(ctx, p->widget_id);
			vals[1] = mkgui_spinbox_get(ctx, p->widget_id2);
		} break;

		case ED_PK_FLAG: {
			uint32_t *fld = (uint32_t *)((char *)w + p->offset);
			if(mkgui_checkbox_get(ctx, p->widget_id)) {
				*fld |= p->flag_bit;
			} else {
				*fld &= ~p->flag_bit;
			}
		} break;

		case ED_PK_ALIGN: {
			int32_t sel = mkgui_dropdown_get(ctx, p->widget_id);
			if(sel < 0) {
				sel = 0;
			}
			w->flags = (w->flags & ~MKGUI_ALIGN_MASK) | ((uint32_t)sel << 25);
		} break;

		case ED_PK_TB_MODE: {
			int32_t sel = mkgui_dropdown_get(ctx, p->widget_id);
			if(sel < 0) {
				sel = 0;
			}
			w->style = (w->style & ~MKGUI_TOOLBAR_MODE_MASK) | ((uint32_t)sel & MKGUI_TOOLBAR_MODE_MASK);
		} break;

		default: break;
	}
}

// ---------------------------------------------------------------------------
// Tab state helpers
// ---------------------------------------------------------------------------

// [=]===^=[ ed_get_active_tab ]===================================[=]
static uint32_t ed_get_active_tab(uint32_t tabs_id) {
	for(uint32_t i = 0; i < ed.tab_state_count; ++i) {
		if(ed.tab_states[i].tabs_id == tabs_id) {
			return ed.tab_states[i].active_id;
		}
	}
	for(uint32_t i = 0; i < ed.widget_count; ++i) {
		if(ed.widgets[i].type == MKGUI_TAB && ed.widgets[i].parent_id == tabs_id) {
			return ed.widgets[i].id;
		}
	}
	return 0;
}

// [=]===^=[ ed_set_active_tab ]===================================[=]
static void ed_set_active_tab(uint32_t tabs_id, uint32_t tab_id) {
	for(uint32_t i = 0; i < ed.tab_state_count; ++i) {
		if(ed.tab_states[i].tabs_id == tabs_id) {
			ed.tab_states[i].active_id = tab_id;
			return;
		}
	}

	if(ed.tab_state_count < 32) {
		ed.tab_states[ed.tab_state_count].tabs_id = tabs_id;
		ed.tab_states[ed.tab_state_count].active_id = tab_id;
		++ed.tab_state_count;
	}
}

// [=]===^=[ ed_is_tab_child_visible ]=============================[=]
static uint32_t ed_is_tab_child_visible(uint32_t idx) {
	struct ed_widget *w = &ed.widgets[idx];
	for(uint32_t j = 0; j < ed.widget_count; ++j) {
		if(ed.widgets[j].id == w->parent_id && ed.widgets[j].type == MKGUI_TAB) {
			uint32_t tabs_id = ed.widgets[j].parent_id;
			if(ed_get_active_tab(tabs_id) != ed.widgets[j].id) {
				return 0;
			}
		}
	}
	return 1;
}

// ---------------------------------------------------------------------------
// Widget data helpers
// ---------------------------------------------------------------------------

// [=]===^=[ ed_find_widget_data ]=================================[=]
static struct ed_widget_data *ed_find_widget_data(uint32_t widget_id) {
	for(uint32_t i = 0; i < ed.widget_data_count; ++i) {
		if(ed.widget_data[i].widget_id == widget_id) {
			return &ed.widget_data[i];
		}
	}
	return NULL;
}

// [=]===^=[ ed_get_or_create_widget_data ]========================[=]
static struct ed_widget_data *ed_get_or_create_widget_data(uint32_t widget_id) {
	struct ed_widget_data *d = ed_find_widget_data(widget_id);
	if(d) {
		return d;
	}

	if(ed.widget_data_count >= ED_MAX_DATA_WIDGETS) {
		return NULL;
	}
	d = &ed.widget_data[ed.widget_data_count++];
	memset(d, 0, sizeof(*d));
	d->widget_id = widget_id;
	return d;
}

// [=]===^=[ ed_remove_widget_data ]===============================[=]
static void ed_remove_widget_data(uint32_t widget_id) {
	for(uint32_t i = 0; i < ed.widget_data_count; ++i) {
		if(ed.widget_data[i].widget_id == widget_id) {
			if(i + 1 < ed.widget_data_count) {
				memmove(&ed.widget_data[i], &ed.widget_data[i + 1], (ed.widget_data_count - i - 1) * sizeof(struct ed_widget_data));
			}
			--ed.widget_data_count;
			return;
		}
	}
}

// ---------------------------------------------------------------------------
// Undo / redo
// ---------------------------------------------------------------------------

// [=]===^=[ ed_push_undo ]=======================================[=]
static void ed_push_undo(void) {
	struct ed_snapshot *snap = &ed.undo[ed.undo_pos % ED_MAX_UNDO];
	memcpy(snap->widgets, ed.widgets, sizeof(struct ed_widget) * ed.widget_count);
	snap->widget_count = ed.widget_count;
	++ed.undo_pos;
	ed.undo_count = ed.undo_pos;
}

// [=]===^=[ ed_undo ]============================================[=]
static void ed_undo(void) {
	if(ed.undo_pos == 0) {
		return;
	}
	--ed.undo_pos;
	struct ed_snapshot *snap = &ed.undo[ed.undo_pos % ED_MAX_UNDO];
	memcpy(ed.widgets, snap->widgets, sizeof(struct ed_widget) * snap->widget_count);
	ed.widget_count = snap->widget_count;
	ed.selected = -1;
}

// [=]===^=[ ed_redo ]============================================[=]
static void ed_redo(void) {
	if(ed.undo_pos >= ed.undo_count) {
		return;
	}
	++ed.undo_pos;
	if(ed.undo_pos < ed.undo_count) {
		struct ed_snapshot *snap = &ed.undo[ed.undo_pos % ED_MAX_UNDO];
		memcpy(ed.widgets, snap->widgets, sizeof(struct ed_widget) * snap->widget_count);
		ed.widget_count = snap->widget_count;
	}
	ed.selected = -1;
}

