// [=]===^=[ ed_test_gui ]========================================[=]
static void ed_test_gui(struct mkgui_ctx *editor_ctx) {
	if(ed.widget_count == 0) {
		return;
	}

	struct mkgui_widget *test_widgets = ed_scratch.test_widgets;
	for(uint32_t i = 0; i < ed.widget_count; ++i) {
		struct ed_widget *ew = &ed.widgets[i];
		struct mkgui_widget *tw = &test_widgets[i];
		tw->type = ew->type;
		tw->id = ew->id;
		size_t slen = strlen(ew->label);
		if(slen >= MKGUI_MAX_TEXT) {
			slen = MKGUI_MAX_TEXT - 1;
		}
		memcpy(tw->label, ew->label, slen);
		tw->label[slen] = '\0';
		tw->parent_id = ew->parent_id;
		memcpy(tw->icon, ew->icon, MKGUI_ICON_NAME_LEN);
		{
			int32_t lx, ly;
			ed_convert_to_layout(i, &lx, &ly, &tw->w, &tw->h);
		}
		tw->flags = ew->flags;
		tw->style = ew->style;
		tw->weight = ew->weight;
		tw->margin_l = ew->margin_l;
		tw->margin_t = ew->margin_t;
		tw->margin_r = ew->margin_r;
		tw->margin_b = ew->margin_b;
		tw->label_tw = -1;
	}

	int32_t test_w = 800, test_h = 600;
	char *test_title = "Test";
	for(uint32_t i = 0; i < ed.widget_count; ++i) {
		if(test_widgets[i].type == MKGUI_WINDOW) {
			if(test_widgets[i].w > 0) {
				test_w = test_widgets[i].w;
			}

			if(test_widgets[i].h > 0) {
				test_h = test_widgets[i].h;
			}

			if(test_widgets[i].label[0]) {
				test_title = test_widgets[i].label;
			}
			break;
		}
	}
	struct mkgui_ctx *test = mkgui_create_child(editor_ctx, test_widgets, ed.widget_count, test_title, test_w, test_h);
	if(!test) {
		return;
	}

	for(uint32_t i = 0; i < ed.widget_count; ++i) {
		struct ed_widget *ew = &ed.widgets[i];
		struct ed_widget_data *d = ed_find_widget_data(ew->id);

		switch(ew->type) {
			case MKGUI_DROPDOWN: {
				if(d && d->item_count > 0) {
					char *items[ED_MAX_DATA_ITEMS];
					for(uint32_t j = 0; j < d->item_count; ++j) {
						items[j] = d->items[j];
					}
					mkgui_dropdown_setup(test, ew->id, items, d->item_count);
				}
			} break;

			case MKGUI_COMBOBOX: {
				if(d && d->item_count > 0) {
					char *items[ED_MAX_DATA_ITEMS];
					for(uint32_t j = 0; j < d->item_count; ++j) {
						items[j] = d->items[j];
					}
					mkgui_combobox_setup(test, ew->id, items, d->item_count);
				}
			} break;

			case MKGUI_LISTVIEW: {
				struct mkgui_column cols[] = {
					{ "Column", 200, MKGUI_CELL_TEXT },
				};
				mkgui_listview_setup(test, ew->id, 5, 1, cols, ed_test_row_cb, NULL);
			} break;

			case MKGUI_TREEVIEW: {
				mkgui_treeview_setup(test, ew->id);
				mkgui_treeview_add(test, ew->id, 1, 0, "Node 1");
				mkgui_treeview_add(test, ew->id, 2, 1, "Child 1");
				mkgui_treeview_add(test, ew->id, 3, 1, "Child 2");
				mkgui_treeview_add(test, ew->id, 4, 0, "Node 2");
			} break;

			case MKGUI_ITEMVIEW: {
				mkgui_itemview_setup(test, ew->id, 5, MKGUI_VIEW_ICON, ed_test_item_label_cb, ed_test_item_icon_cb, NULL);
			} break;

			case MKGUI_GRIDVIEW: {
				struct mkgui_grid_column gcols[] = {
					{ "Column 1", 100, MKGUI_GRID_TEXT },
					{ "Check", 60, MKGUI_GRID_CHECK },
				};
				mkgui_gridview_setup(test, ew->id, 10, 2, gcols, (mkgui_grid_cell_cb)ed_test_row_cb, NULL);
			} break;

			case MKGUI_RICHLIST: {
				mkgui_richlist_setup(test, ew->id, 20, 56, ed_test_richlist_cb, NULL);
			} break;

			case MKGUI_SLIDER: {
				mkgui_slider_setup(test, ew->id, 0, 100, 50);
			} break;

			case MKGUI_SPINBOX: {
				mkgui_spinbox_setup(test, ew->id, 0, 100, 0, 1);
			} break;

			case MKGUI_SCROLLBAR: {
				mkgui_scrollbar_setup(test, ew->id, 100, 10);
			} break;

			case MKGUI_STATUSBAR: {
				uint32_t sc = (d && d->item_count > 0) ? d->item_count : 1;
				int32_t widths[ED_MAX_DATA_ITEMS];
				if(d && d->item_count > 0) {
					for(uint32_t j = 0; j < d->item_count; ++j) {
						widths[j] = atoi(d->items[j]);
					}
				} else {
					widths[0] = -1;
				}
				mkgui_statusbar_setup(test, ew->id, sc, widths);
				mkgui_statusbar_set(test, ew->id, 0, "Ready");
			} break;

			case MKGUI_PROGRESS: {
				mkgui_progress_setup(test, ew->id, 100);
				mkgui_progress_set(test, ew->id, 50);
			} break;

			case MKGUI_METER: {
				mkgui_meter_setup(test, ew->id, 100);
				mkgui_meter_set(test, ew->id, 50);
			} break;

			case MKGUI_PATHBAR: {
				mkgui_pathbar_set(test, ew->id, "/home/user/documents");
			} break;

			default: {
			} break;
		}
	}

	struct mkgui_event ev;
	uint32_t running = 1;
	while(running) {
		while(mkgui_poll(test, &ev)) {
			if(ev.type == MKGUI_EVENT_CLOSE) {
				running = 0;
			}
		}
		mkgui_wait(test);
	}

	mkgui_destroy_child(test);
}

